#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void dfs(vector<vector<int>>& graph, int source, vector<bool>& visited) {
        visited[source] = true;
        cout << source << '\n';
        for (int neighbor : graph[source]) {
            if (!visited[neighbor]) {
                dfs(graph, neighbor, visited);
            }
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> graph(V);
    for (int i = 0; i < E; i++) {
        int u, v;
        if (!(cin >> u >> v)) return 0;
        graph[u].push_back(v);
        graph[v].push_back(u);
    }
    int source;
    if (!(cin >> source)) return 0;
    Solution sol;
    vector<bool> visited(V, false);
    sol.dfs(graph, source, visited);
    return 0;
}
